INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2178, 215259, 12, 2334, '[转贴]日本鬼子的“立邦漆”，想了解真相的进来', '日本鬼子的“立邦漆”，想了解真相的进来
<br>
<br>  “立邦漆”是根据“Nippon Paint”的译音，在中国注册的商标，在日本的汉字商标就是“日本漆”，怕刺激中国人没有敢直接拿到中国。其生产厂家日本油漆公 (Nippon Paint Co.)，是当年为了为鬼子海军提供专用舰船涂料而建立的一家军工企业 ，在明治、大正、昭和年间，随着鬼子海军的发展，而逐渐发展成为的一家大型涂 料公司， 到太平洋战争为止，已经成为当时日本最大的涂料公司。在美军的轰炸中， 其 在东京 大阪的主力工厂和海外基地几乎全部被夷为平地。随着日本军国主义的完 蛋，这个主 要为鬼子海军和其他军事目的服务的鬼子涂料老大也几乎完蛋，跌倒了日本第5位，并且在“立邦”进入中国之前一直没有根本改观。
<br>
<br>   中国改革开放后，日本油漆公司(Nippon Paint Co.)这个依靠沾满中国人民鲜血的鬼 子海军而发迹的涂料公司，改头换面来到了中国！将日本油漆公司(Nippon Paint Co.)的中文名称改为立邦涂料公司，将“日本油漆”商标改为“立邦漆”。 通过大量的广告促销，在中国逐渐占领了绝大多数的中高端市场！其质次价高，在行 业内早就不是什么秘密，尤其是到处可见的低端产品，其质量远远低于国产 同 类产 品。但销路奇好、且价格还远远高于同类国产涂料！
<br>   更可怕的是，众多的中国人对此一无所知。涂料首选“立邦”，客观上“立邦”已经成为中国老百姓的选择涂料的一个重要标准！ 仅仅10数年，鬼子的“立邦”涂料，就通过垄断中国的中高端市场，从一个默 默无闻、 仅仅日本排行第五的小厂进人了世界涂料10强！！！！
<br>    “立邦”在中国到底有多大的能耐，讲一个真实的故事就可以看出其中的端 倪！ 为了环保和最大限度的减少涂料对人体的伤害，我们最新制定的涂料国标准准备是 100gVOC。但在最后关头，这个业内老大“立邦”发话了，认为标准太高声生 产 不出来！最后竟是我们的国家标准屈从于鬼子的淫威，变成了200gVOC，也由此引发了一 场标准 之争。实际上，欧美涂料厂家的VOC早就控制在50g以下，适用儿童使用的涂 料，更是几乎为0。
<br>
<br>     鬼子还是东西吗？！', '日本鬼子的“立邦漆”，想了解真相的进来

“立邦漆”是根据“Nippon Paint”的译音，在中国注册的商标，在日本的汉字商标就是“日本漆”，怕刺激中国人没有敢直接拿到中国。其生产厂家日本油漆公 (Nippon Paint Co.)，是当年为了为鬼子海军提供专用舰船涂料而建立的一家军工企业 ，在明治、大正、昭和年间，随着鬼子海军的发展，而逐渐发展成为的一家大型涂 料公司， 到太平洋战争为止，已经成为当时日本最大的涂料公司。在美军的轰炸中， 其 在东京 大阪的主力工厂和海外基地几乎全部被夷为平地。随着日本军国主义的完 蛋，这个主 要为鬼子海军和其他军事目的服务的鬼子涂料老大也几乎完蛋，跌倒了日本第5位，并且在“立邦”进入中国之前一直没有根本改观。

中国改革开放后，日本油漆公司(Nippon Paint Co.)这个依靠沾满中国人民鲜血的鬼 子海军而发迹的涂料公司，改头换面来到了中国！将日本油漆公司(Nippon Paint Co.)的中文名称改为立邦涂料公司，将“日本油漆”商标改为“立邦漆”。 通过大量的广告促销，在中国逐渐占领了绝大多数的中高端市场！其质次价高，在行 业内早就不是什么秘密，尤其是到处可见的低端产品，其质量远远低于国产 同 类产 品。但销路奇好、且价格还远远高于同类国产涂料！

更可怕的是，众多的中国人对此一无所知。涂料首选“立邦”，客观上“立邦”已经成为中国老百姓的选择涂料的一个重要标准！ 仅仅10数年，鬼子的“立邦”涂料，就通过垄断中国的中高端市场，从一个默 默无闻、 仅仅日本排行第五的小厂进人了世界涂料10强！！！！

“立邦”在中国到底有多大的能耐，讲一个真实的故事就可以看出其中的端 倪！ 为了环保和最大限度的减少涂料对人体的伤害，我们最新制定的涂料国标准准备是 100gVOC。但在最后关头，这个业内老大“立邦”发话了，认为标准太高声生 产 不出来！最后竟是我们的国家标准屈从于鬼子的淫威，变成了200gVOC，也由此引发了一 场标准 之争。实际上，欧美涂料厂家的VOC早就控制在50g以下，适用儿童使用的涂 料，更是几乎为0。

鬼子还是东西吗？！', NULL, '2003-10-08 14:40:00', 3, '20031017114224_bbsid_215259_board_12_56f6b0190e.html', '20031017114224');
